-- Name: trg_touch_chat_room_updated_at(); Type: FUNCTION; Schema: public; Owner: root
--

CREATE FUNCTION public.trg_touch_chat_room_updated_at() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE chat_rooms
  SET updated_at = COALESCE(NEW.sent_at, CURRENT_TIMESTAMP)
  WHERE room_id = NEW.room_id;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.trg_touch_chat_room_updated_at() OWNER TO root;

